create table if not exists public.order_import_batches (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, created_by uuid references public.profiles(id), filename text not null, marketplace text not null, mapping jsonb not null default '{}'::jsonb, status text not null default 'previewed' check(status in ('previewed','review_required','ready','importing','completed','partially_failed','failed')), accepted_rows integer not null default 0, rejected_rows integer not null default 0, unresolved_rows integer not null default 0, summary jsonb not null default '{}'::jsonb, idempotency_key text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(business_id,idempotency_key));
create table if not exists public.order_import_rows (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, batch_id uuid not null references public.order_import_batches(id) on delete cascade, row_number integer not null, source_values jsonb not null, status text not null default 'accepted' check(status in ('accepted','rejected','duplicate','review_required','imported','failed','cancelled')), error text, order_id uuid references public.orders(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(batch_id,row_number));
alter table public.order_import_batches enable row level security; alter table public.order_import_rows enable row level security;
create policy "import batch read" on public.order_import_batches for select using(public.is_business_member(business_id)); create policy "import batch write" on public.order_import_batches for all using(public.has_business_role(business_id,array['owner','admin','operations'])) with check(public.has_business_role(business_id,array['owner','admin','operations']));
create policy "import row read" on public.order_import_rows for select using(public.is_business_member(business_id)); create policy "import row write" on public.order_import_rows for all using(public.has_business_role(business_id,array['owner','admin','operations'])) with check(public.has_business_role(business_id,array['owner','admin','operations']));
create index if not exists order_import_rows_batch_status_idx on public.order_import_rows(batch_id,status);
